                [".txt"] = "text/plain",
                [".csv"] = "text/csv",
                [".jpg"] = "image/jpeg",
                [".jpeg"] = "image/jpeg",
                [".png"] = "image/png",
                [".gif"] = "image/gif",
                [".bmp"] = "image/bmp",
                [".webp"] = "image/webp",
                [".svg"] = "image/svg+xml"
